@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"
          @bind:after="OnContentChanged"></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow" disabled="@(!isDirty)">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private bool isDirty;
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Notepad.razor.js");

            var restored = await module.InvokeAsync<string?>("load");
            if (!string.IsNullOrEmpty(restored))
            {
                content = restored;
                savedContent = restored;
                StateHasChanged();
            }

            autoSaveTimer = new System.Threading.Timer(
                async _ => await InvokeAsync(AutoSave), null,
                TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async Task OnContentChanged()
    {
        isDirty = content != savedContent;
        if (module is not null)
        {
            await module.InvokeVoidAsync("setDirty", isDirty);
        }
    }

    private async Task AutoSave()
    {
        if (isDirty)
        {
            await Save();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("save", content);
            savedContent = content;
            isDirty = false;
            lastSavedAt = DateTime.Now;
            await module.InvokeVoidAsync("setDirty", false);
        }
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        isDirty = false;
        lastSavedAt = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("clear");
            await module.InvokeVoidAsync("setDirty", false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Dispose();
        if (module is not null)
        {
            await module.InvokeVoidAsync("setDirty", false);
            await module.DisposeAsync();
        }
    }
}

const STORAGE_KEY = "notepad-content";

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function load() {
    return localStorage.getItem(STORAGE_KEY);
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
}

export function setDirty(dirty) {
    if (dirty) {
        window.onbeforeunload = () => true;
    } else {
        window.onbeforeunload = null;
    }
}

